sys_script_fix.script:
var count = 0;
//GET BAN ACCOUNTS THAT WERE MAPPED WITH MDMD3 Account number via transformation map
var grBAN = new GlideRecord('customer_account');
grBAN.addEncodedQuery('u_account_number_mdm3_0!=NULL^u_account_category=ban^u_customer_migrated_mdm3_0=true');
//grBAN.setLimit(100);
grBAN.query();
while (grBAN.next()) {

    //GET releted CAN account created from MDM3 and populate expected attrs into BAN.
    var grCAN = new GlideRecord('customer_account');
    grCAN.addEncodedQuery("u_account_number_mdm3_0!=NULL^u_account_number_mdm3_0=" + grBAN.getValue('u_account_number_mdm3_0')+"^ u_account_category=can");
    grCAN.orderBy('u_account_number_mdm3_0');
    grCAN.setLimit(1);
    grCAN.query();
    if (grCAN.next()) {
        grBAN.setValue('u_ucm_id', grCAN.getValue('u_mdm_id')); //CAN MDM ID moves to BAN UCM ID
        grBAN.setValue('u_account_number', grCAN.getValue('u_account_number_mdm3_0')); //CAN MDM3 Number into BAN Number
        grBAN.setValue('u_parent_legal_account', grCAN.getUniqueValue());
        grBAN.update();
        count++;
    }

}

gs.info("total BAN accounts updated:" + count);
